public void ProcessPaymentBatch(IEnumerable<decimal> amounts)
{
    var buffer = new decimal[amounts.Count()]; // heap allocation per call
    // ...
}

// ✅ GOOD - stack allocation for small known-size buffers
public void ProcessPaymentBatch(ReadOnlySpan<decimal> amounts)
{
    Span<decimal> sorted = stackalloc decimal[amounts.Length]; // stack only
    amounts.CopyTo(sorted);
    sorted.Sort();
    // no GC pressure
}

